import { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell, HeadingLevel, AlignmentType, WidthType, BorderStyle, ShadingType } from 'docx';
import { writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..', 'data');
const OUTPUT = 'C:\\Users\\Administrator\\Desktop\\外贸跟进战报_2026-04-30.docx';

// Load data
const fc = JSON.parse(await import('fs').then(fs => fs.readFileSync(join(DATA_DIR, fs.readdirSync(DATA_DIR).filter(f => f.includes('全量客户分类')).sort().reverse()[0]), 'utf8')));
const p0 = fc.customers.filter(c => c.priority === 'P0');
const p1 = fc.customers.filter(c => c.priority === 'P1');
const p2 = fc.customers.filter(c => c.priority === 'P2');
const p3 = fc.customers.filter(c => c.priority === 'P3');

// Helper: text run
const T = (text, opts = {}) => new TextRun({ text, ...opts });
const TB = (text) => T(text, { bold: true });
const TS = (text) => T(text, { size: 20 });

// Helper: colored cell
